import type { Express } from "express";
import { createServer, type Server } from "http";
import { storage } from "./storage";
import bcrypt from "bcrypt";
import jwt from "jsonwebtoken";
import multer from "multer";
import path from "path";
import { z } from "zod";
import { insertUserSchema, insertPropertySchema, insertContractSchema, insertPaymentSchema, insertDocumentSchema, insertDisputeSchema } from "@shared/schema";

const upload = multer({ dest: 'uploads/' });
const JWT_SECRET = process.env.JWT_SECRET || "your-secret-key";

// Middleware to verify JWT token
const authenticateToken = (req: any, res: any, next: any) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    return res.status(401).json({ message: 'Access token required' });
  }

  jwt.verify(token, JWT_SECRET, (err: any, user: any) => {
    if (err) {
      return res.status(403).json({ message: 'Invalid token' });
    }
    req.user = user;
    next();
  });
};

// Role-based middleware
const requireRole = (roles: string[]) => {
  return (req: any, res: any, next: any) => {
    if (!req.user || !roles.includes(req.user.role)) {
      return res.status(403).json({ message: 'Insufficient permissions' });
    }
    next();
  };
};

export async function registerRoutes(app: Express): Promise<Server> {

  // Authentication routes
  app.post("/api/auth/register", async (req, res) => {
    try {
      const validatedData = insertUserSchema.parse(req.body);

      // Check if user exists
      const existingUser = await storage.getUserByEmail(validatedData.email);
      if (existingUser) {
        return res.status(400).json({ message: "User already exists" });
      }

      // Hash password
      const hashedPassword = await bcrypt.hash(validatedData.password, 12);

      const user = await storage.createUser({
        ...validatedData,
        password: hashedPassword,
      });

      // Generate JWT token
      const token = jwt.sign(
        { userId: user.id, email: user.email, role: user.role },
        JWT_SECRET,
        { expiresIn: '24h' }
      );

      res.status(201).json({ 
        user: { 
          id: user.id, 
          email: user.email, 
          fullName: user.fullName, 
          role: user.role,
          verificationStatus: user.verificationStatus 
        }, 
        token 
      });
    } catch (error) {
      console.error("Registration error:", error);
      res.status(400).json({ message: "Invalid data provided" });
    }
  });

  app.post("/api/auth/login", async (req, res) => {
    try {
      const { email, password } = req.body;

      const user = await storage.getUserByEmail(email);
      if (!user) {
        return res.status(401).json({ message: "Invalid credentials" });
      }

      const isValidPassword = await bcrypt.compare(password, user.password);
      if (!isValidPassword) {
        return res.status(401).json({ message: "Invalid credentials" });
      }

      const token = jwt.sign(
        { userId: user.id, email: user.email, role: user.role },
        JWT_SECRET,
        { expiresIn: '24h' }
      );

      res.json({ 
        user: { 
          id: user.id, 
          email: user.email, 
          fullName: user.fullName, 
          role: user.role,
          verificationStatus: user.verificationStatus 
        }, 
        token 
      });
    } catch (error) {
      console.error("Login error:", error);
      res.status(500).json({ message: "Internal server error" });
    }
  });

  app.get("/api/auth/me", authenticateToken, async (req, res) => {
    try {
      const user = await storage.getUser(req.user.userId);
      if (!user) {
        return res.status(404).json({ message: "User not found" });
      }

      res.json({ 
        id: user.id, 
        email: user.email, 
        fullName: user.fullName, 
        role: user.role,
        verificationStatus: user.verificationStatus,
        phone: user.phone,
        cnicNumber: user.cnicNumber,
        profileImage: user.profileImage
      });
    } catch (error) {
      console.error("Get user error:", error);
      res.status(500).json({ message: "Internal server error" });
    }
  });

  // Properties routes
  app.get("/api/properties", async (req, res) => {
    try {
      const { city, propertyType, minRent, maxRent, bedrooms, limit = 20, offset = 0 } = req.query;

      const filters = {
        city: city as string,
        propertyType: propertyType as string,
        minRent: minRent ? Number(minRent) : undefined,
        maxRent: maxRent ? Number(maxRent) : undefined,
        bedrooms: bedrooms ? Number(bedrooms) : undefined,
        isAvailable: true,
        limit: Number(limit),
        offset: Number(offset),
      };

      const properties = await storage.getProperties(filters);
      res.json(properties);
    } catch (error) {
      console.error("Get properties error:", error);
      res.status(500).json({ message: "Internal server error" });
    }
  });

  app.get("/api/properties/:id", async (req, res) => {
    try {
      const property = await storage.getProperty(req.params.id);
      if (!property) {
        return res.status(404).json({ message: "Property not found" });
      }
      res.json(property);
    } catch (error) {
      console.error("Get property error:", error);
      res.status(500).json({ message: "Internal server error" });
    }
  });

  app.post("/api/properties", authenticateToken, requireRole(['landlord']), async (req, res) => {
    try {
      const validatedData = insertPropertySchema.parse({
        ...req.body,
        landlordId: req.user.userId,
      });

      const property = await storage.createProperty(validatedData);
      res.status(201).json(property);
    } catch (error) {
      console.error("Create property error:", error);
      res.status(400).json({ message: "Invalid data provided" });
    }
  });

  app.put("/api/properties/:id", authenticateToken, requireRole(['landlord']), async (req, res) => {
    try {
      const property = await storage.getProperty(req.params.id);
      if (!property || property.landlordId !== req.user.userId) {
        return res.status(404).json({ message: "Property not found" });
      }

      const updatedProperty = await storage.updateProperty(req.params.id, req.body);
      res.json(updatedProperty);
    } catch (error) {
      console.error("Update property error:", error);
      res.status(400).json({ message: "Invalid data provided" });
    }
  });

  app.delete("/api/properties/:id", authenticateToken, requireRole(['landlord']), async (req, res) => {
    try {
      const property = await storage.getProperty(req.params.id);
      if (!property || property.landlordId !== req.user.userId) {
        return res.status(404).json({ message: "Property not found" });
      }

      await storage.deleteProperty(req.params.id);
      res.status(204).send();
    } catch (error) {
      console.error("Delete property error:", error);
      res.status(500).json({ message: "Internal server error" });
    }
  });

  // Contracts routes
  app.get("/api/contracts", authenticateToken, async (req, res) => {
    try {
      const filters: any = {};

      if (req.user.role === 'landlord') {
        filters.landlordId = req.user.userId;
      } else if (req.user.role === 'tenant') {
        filters.tenantId = req.user.userId;
      }

      const contracts = await storage.getContracts(filters);
      res.json(contracts);
    } catch (error) {
      console.error("Get contracts error:", error);
      res.status(500).json({ message: "Internal server error" });
    }
  });

  app.post("/api/contracts", authenticateToken, requireRole(['landlord']), async (req, res) => {
    try {
      const validatedData = insertContractSchema.parse({
        ...req.body,
        landlordId: req.user.userId,
      });

      const contract = await storage.createContract(validatedData);
      res.status(201).json(contract);
    } catch (error) {
      console.error("Create contract error:", error);
      res.status(400).json({ message: "Invalid data provided" });
    }
  });

  app.put("/api/contracts/:id", authenticateToken, async (req, res) => {
    try {
      const contract = await storage.getContract(req.params.id);
      if (!contract) {
        return res.status(404).json({ message: "Contract not found" });
      }

      // Check permissions
      if (req.user.role !== 'admin' && 
          contract.landlordId !== req.user.userId && 
          contract.tenantId !== req.user.userId) {
        return res.status(403).json({ message: "Insufficient permissions" });
      }

      const updatedContract = await storage.updateContract(req.params.id, req.body);
      res.json(updatedContract);
    } catch (error) {
      console.error("Update contract error:", error);
      res.status(400).json({ message: "Invalid data provided" });
    }
  });

  // Payments routes
  app.get("/api/payments", authenticateToken, async (req, res) => {
    try {
      const filters: any = {};

      if (req.user.role === 'landlord') {
        filters.landlordId = req.user.userId;
      } else if (req.user.role === 'tenant') {
        filters.tenantId = req.user.userId;
      }

      const payments = await storage.getPayments(filters);
      res.json(payments);
    } catch (error) {
      console.error("Get payments error:", error);
      res.status(500).json({ message: "Internal server error" });
    }
  });

  app.post("/api/payments", authenticateToken, async (req, res) => {
    try {
      const validatedData = insertPaymentSchema.parse(req.body);
      const payment = await storage.createPayment(validatedData);
      res.status(201).json(payment);
    } catch (error) {
      console.error("Create payment error:", error);
      res.status(400).json({ message: "Invalid data provided" });
    }
  });

  app.put("/api/payments/:id", authenticateToken, async (req, res) => {
    try {
      const payment = await storage.getPayment(req.params.id);
      if (!payment) {
        return res.status(404).json({ message: "Payment not found" });
      }

      const updatedPayment = await storage.updatePayment(req.params.id, req.body);
      res.json(updatedPayment);
    } catch (error) {
      console.error("Update payment error:", error);
      res.status(400).json({ message: "Invalid data provided" });
    }
  });

  // Documents routes
  app.post("/api/documents", authenticateToken, upload.single('file'), async (req, res) => {
    try {
      if (!req.file) {
        return res.status(400).json({ message: "No file uploaded" });
      }

      const documentData = {
        userId: req.user.userId,
        type: req.body.type,
        fileName: req.file.originalname,
        filePath: req.file.path,
        fileSize: req.file.size,
        mimeType: req.file.mimetype,
        propertyId: req.body.propertyId || null,
        contractId: req.body.contractId || null,
      };

      const document = await storage.createDocument(documentData);
      res.status(201).json(document);
    } catch (error) {
      console.error("Upload document error:", error);
      res.status(500).json({ message: "Internal server error" });
    }
  });

  app.get("/api/documents", authenticateToken, async (req, res) => {
    try {
      const filters: any = {};

      if (req.user.role !== 'admin') {
        filters.userId = req.user.userId;
      }

      const documents = await storage.getDocuments(filters);
      res.json(documents);
    } catch (error) {
      console.error("Get documents error:", error);
      res.status(500).json({ message: "Internal server error" });
    }
  });

  // Admin routes
  app.get("/api/admin/users", authenticateToken, requireRole(['admin']), async (req, res) => {
    try {
      // This would need a getAllUsers method in storage
      res.json([]);
    } catch (error) {
      console.error("Get users error:", error);
      res.status(500).json({ message: "Internal server error" });
    }
  });

  app.put("/api/admin/users/:id/verification", authenticateToken, requireRole(['admin']), async (req, res) => {
    try {
      const { status } = req.body;
      const user = await storage.updateUserVerificationStatus(req.params.id, status);
      res.json(user);
    } catch (error) {
      console.error("Update verification error:", error);
      res.status(400).json({ message: "Invalid data provided" });
    }
  });

  // Dashboard stats routes
  app.get("/api/dashboard/stats", authenticateToken, async (req, res) => {
    try {
      let stats;

      if (req.user.role === 'landlord') {
        stats = await storage.getLandlordStats(req.user.userId);
      } else if (req.user.role === 'tenant') {
        stats = await storage.getTenantStats(req.user.userId);
      } else if (req.user.role === 'admin') {
        stats = await storage.getAdminStats();
      }

      res.json(stats);
    } catch (error) {
      console.error("Get dashboard stats error:", error);
      res.status(500).json({ message: "Internal server error" });
    }
  });

  // Disputes routes
  app.get("/api/disputes", authenticateToken, async (req, res) => {
    try {
      const filters: any = {};

      if (req.user.role !== 'admin') {
        filters.raisedBy = req.user.userId;
      }

      const disputes = await storage.getDisputes(filters);
      res.json(disputes);
    } catch (error) {
      console.error("Get disputes error:", error);
      res.status(500).json({ message: "Internal server error" });
    }
  });

  app.post("/api/disputes", authenticateToken, async (req, res) => {
    try {
      const validatedData = insertDisputeSchema.parse({
        ...req.body,
        raisedBy: req.user.userId,
      });

      const dispute = await storage.createDispute(validatedData);
      res.status(201).json(dispute);
    } catch (error) {
      console.error("Create dispute error:", error);
      res.status(400).json({ message: "Invalid data provided" });
    }
  });

  const httpServer = createServer(app);
  return httpServer;
}

server/storage.ts.content:
import { 
  users, properties, contracts, payments, documents, disputes, reviews,
  type User, type InsertUser, 
  type Property, type InsertProperty,
  type Contract, type InsertContract,
  type Payment, type InsertPayment,
  type Document, type InsertDocument,
  type Dispute, type InsertDispute,
  type Review, type InsertReview
} from "@shared/schema";
import { db } from "./db";
import { eq, and, or, desc, asc, like, gte, lte, sql } from "drizzle-orm";

export interface IStorage {
  // User methods
  getUser(id: string): Promise<User | undefined>;
  getUserByEmail(email: string): Promise<User | undefined>;
  createUser(user: InsertUser): Promise<User>;
  updateUser(id: string, updates: Partial<InsertUser>): Promise<User>;
  updateUserVerificationStatus(id: string, status: "pending" | "verified" | "rejected"): Promise<User>;

  // Property methods
  getProperties(filters?: {
    city?: string;
    propertyType?: string;
    minRent?: number;
    maxRent?: number;
    bedrooms?: number;
    isAvailable?: boolean;
    limit?: number;
    offset?: number;
  }): Promise<Property[]>;
  getProperty(id: string): Promise<Property | undefined>;
  getPropertiesByLandlord(landlordId: string): Promise<Property[]>;
  createProperty(property: InsertProperty): Promise<Property>;
  updateProperty(id: string, updates: Partial<InsertProperty>): Promise<Property>;
  deleteProperty(id: string): Promise<void>;

  // Contract methods
  getContracts(filters?: {
    landlordId?: string;
    tenantId?: string;
    status?: string;
    limit?: number;
    offset?: number;
  }): Promise<Contract[]>;
  getContract(id: string): Promise<Contract | undefined>;
  createContract(contract: InsertContract): Promise<Contract>;
  updateContract(id: string, updates: Partial<InsertContract>): Promise<Contract>;

  // Payment methods
  getPayments(filters?: {
    contractId?: string;
    tenantId?: string;
    landlordId?: string;
    status?: string;
    limit?: number;
    offset?: number;
  }): Promise<Payment[]>;
  getPayment(id: string): Promise<Payment | undefined>;
  createPayment(payment: InsertPayment): Promise<Payment>;
  updatePayment(id: string, updates: Partial<InsertPayment>): Promise<Payment>;

  // Document methods
  getDocuments(filters?: {
    userId?: string;
    propertyId?: string;
    contractId?: string;
    type?: string;
  }): Promise<Document[]>;
  getDocument(id: string): Promise<Document | undefined>;
  createDocument(document: InsertDocument): Promise<Document>;
  updateDocument(id: string, updates: Partial<InsertDocument>): Promise<Document>;

  // Dispute methods
  getDisputes(filters?: {
    contractId?: string;
    raisedBy?: string;
    status?: string;
    limit?: number;
    offset?: number;
  }): Promise<Dispute[]>;
  getDispute(id: string): Promise<Dispute | undefined>;
  createDispute(dispute: InsertDispute): Promise<Dispute>;
  updateDispute(id: string, updates: Partial<InsertDispute>): Promise<Dispute>;

  // Review methods
  getReviews(filters?: {
    contractId?: string;
    reviewerId?: string;
    revieweeId?: string;
  }): Promise<Review[]>;
  createReview(review: InsertReview): Promise<Review>;

  // Dashboard stats
  getLandlordStats(landlordId: string): Promise<{
    totalProperties: number;
    activeContracts: number;
    monthlyRevenue: number;
    pendingVerifications: number;
  }>;
  getTenantStats(tenantId: string): Promise<{
    currentRent: number;
    contractStatus: string;
    nextPaymentDate: Date | null;
    savedProperties: number;
  }>;
  getAdminStats(): Promise<{
    totalUsers: number;
    pendingVerifications: number;
    activeContracts: number;
    openDisputes: number;
  }>;
}

export class DatabaseStorage implements IStorage {
  // User methods
  async getUser(id: string): Promise<User | undefined> {
    const [user] = await db.select().from(users).where(eq(users.id, id));
    return user || undefined;
  }

  async getUserByEmail(email: string): Promise<User | undefined> {
    const [user] = await db.select().from(users).where(eq(users.email, email));
    return user || undefined;
  }

  async createUser(insertUser: InsertUser): Promise<User> {
    const [user] = await db
      .insert(users)
      .values(insertUser)
      .returning();
    return user;
  }

  async updateUser(id: string, updates: Partial<InsertUser>): Promise<User> {
    const [user] = await db
      .update(users)
      .set({ ...updates, updatedAt: new Date() })
      .where(eq(users.id, id))
      .returning();
    return user;
  }

  async updateUserVerificationStatus(id: string, status: "pending" | "verified" | "rejected"): Promise<User> {
    const [user] = await db
      .update(users)
      .set({ verificationStatus: status, updatedAt: new Date() })
      .where(eq(users.id, id))
      .returning();
    return user;
  }

  // Property methods
  async getProperties(filters?: {
    city?: string;
    propertyType?: string;
    minRent?: number;
    maxRent?: number;
    bedrooms?: number;
    isAvailable?: boolean;
    limit?: number;
    offset?: number;
  }): Promise<Property[]> {
    let query = db.select().from(properties);

    const conditions = [];

    if (filters?.city) {
      conditions.push(like(properties.city, `%${filters.city}%`));
    }
    if (filters?.propertyType) {
      conditions.push(eq(properties.propertyType, filters.propertyType as any));
    }
    if (filters?.minRent) {
      conditions.push(gte(properties.monthlyRent, filters.minRent.toString()));
    }
    if (filters?.maxRent) {
      conditions.push(lte(properties.monthlyRent, filters.maxRent.toString()));
    }
    if (filters?.bedrooms) {
      conditions.push(eq(properties.bedrooms, filters.bedrooms));
    }
    if (filters?.isAvailable !== undefined) {
      conditions.push(eq(properties.isAvailable, filters.isAvailable));
    }

    if (conditions.length > 0) {
      query = query.where(and(...conditions));
    }

    query = query.orderBy(desc(properties.createdAt));

    if (filters?.limit) {
      query = query.limit(filters.limit);
    }
    if (filters?.offset) {
      query = query.offset(filters.offset);
    }

    return await query;
  }

  async getProperty(id: string): Promise<Property | undefined> {
    const [property] = await db.select().from(properties).where(eq(properties.id, id));
    return property || undefined;
  }

  async getPropertiesByLandlord(landlordId: string): Promise<Property[]> {
    return await db.select().from(properties)
      .where(eq(properties.landlordId, landlordId))
      .orderBy(desc(properties.createdAt));
  }

  async createProperty(property: InsertProperty): Promise<Property> {
    const [newProperty] = await db
      .insert(properties)
      .values(property)
      .returning();
    return newProperty;
  }

  async updateProperty(id: string, updates: Partial<InsertProperty>): Promise<Property> {
    const [property] = await db
      .update(properties)
      .set({ ...updates, updatedAt: new Date() })
      .where(eq(properties.id, id))
      .returning();
    return property;
  }

  async deleteProperty(id: string): Promise<void> {
    await db.delete(properties).where(eq(properties.id, id));
  }

  // Contract methods
  async getContracts(filters?: {
    landlordId?: string;
    tenantId?: string;
    status?: string;
    limit?: number;
    offset?: number;
  }): Promise<Contract[]> {
    let query = db.select().from(contracts);

    const conditions = [];

    if (filters?.landlordId) {
      conditions.push(eq(contracts.landlordId, filters.landlordId));
    }
    if (filters?.tenantId) {
      conditions.push(eq(contracts.tenantId, filters.tenantId));
    }
    if (filters?.status) {
      conditions.push(eq(contracts.status, filters.status as any));
    }

    if (conditions.length > 0) {
      query = query.where(and(...conditions));
    }

    query = query.orderBy(desc(contracts.createdAt));

    if (filters?.limit) {
      query = query.limit(filters.limit);
    }
    if (filters?.offset) {
      query = query.offset(filters.offset);
    }

    return await query;
  }

  async getContract(id: string): Promise<Contract | undefined> {
    const [contract] = await db.select().from(contracts).where(eq(contracts.id, id));
    return contract || undefined;
  }

  async createContract(contract: InsertContract): Promise<Contract> {
    const [newContract] = await db
      .insert(contracts)
      .values(contract)
      .returning();
    return newContract;
  }

  async updateContract(id: string, updates: Partial<InsertContract>): Promise<Contract> {
    const [contract] = await db
      .update(contracts)
      .set({ ...updates, updatedAt: new Date() })
      .where(eq(contracts.id, id))
      .returning();
    return contract;
  }

  // Payment methods
  async getPayments(filters?: {
    contractId?: string;
    tenantId?: string;
    landlordId?: string;
    status?: string;
    limit?: number;
    offset?: number;
  }): Promise<Payment[]> {
    let query = db.select().from(payments);

    const conditions = [];

    if (filters?.contractId) {
      conditions.push(eq(payments.contractId, filters.contractId));
    }
    if (filters?.tenantId) {
      conditions.push(eq(payments.tenantId, filters.tenantId));
    }
    if (filters?.landlordId) {
      conditions.push(eq(payments.landlordId, filters.landlordId));
    }
    if (filters?.status) {
      conditions.push(eq(payments.status, filters.status as any));
    }

    if (conditions.length > 0) {
      query = query.where(and(...conditions));
    }

    query = query.orderBy(desc(payments.createdAt));

    if (filters?.limit) {
      query = query.limit(filters.limit);
    }
    if (filters?.offset) {
      query = query.offset(filters.offset);
    }

    return await query;
  }

  async getPayment(id: string): Promise<Payment | undefined> {
    const [payment] = await db.select().from(payments).where(eq(payments.id, id));
    return payment || undefined;
  }

  async createPayment(payment: InsertPayment): Promise<Payment> {
    const [newPayment] = await db
      .insert(payments)
      .values(payment)
      .returning();
    return newPayment;
  }

  async updatePayment(id: string, updates: Partial<InsertPayment>): Promise<Payment> {
    const [payment] = await db
      .update(payments)
      .set({ ...updates, updatedAt: new Date() })
      .where(eq(payments.id, id))
      .returning();
    return payment;
  }

  // Document methods
  async getDocuments(filters?: {
    userId?: string;
    propertyId?: string;
    contractId?: string;
    type?: string;
  }): Promise<Document[]> {
    let query = db.select().from(documents);

    const conditions = [];

    if (filters?.userId) {
      conditions.push(eq(documents.userId, filters.userId));
    }
    if (filters?.propertyId) {
      conditions.push(eq(documents.propertyId, filters.propertyId));
    }
    if (filters?.contractId) {
      conditions.push(eq(documents.contractId, filters.contractId));
    }
    if (filters?.type) {
      conditions.push(eq(documents.type, filters.type));
    }

    if (conditions.length > 0) {
      query = query.where(and(...conditions));
    }

    query = query.orderBy(desc(documents.createdAt));

    return await query;
  }

  async getDocument(id: string): Promise<Document | undefined> {
    const [document] = await db.select().from(documents).where(eq(documents.id, id));
    return document || undefined;
  }

  async createDocument(document: InsertDocument): Promise<Document> {
    const [newDocument] = await db
      .insert(documents)
      .values(document)
      .returning();
    return newDocument;
  }

  async updateDocument(id: string, updates: Partial<InsertDocument>): Promise<Document> {
    const [document] = await db
      .update(documents)
      .set(updates)
      .where(eq(documents.id, id))
      .returning();
    return document;
  }

  // Dispute methods
  async getDisputes(filters?: {
    contractId?: string;
    raisedBy?: string;
    status?: string;
    limit?: number;
    offset?: number;
  }): Promise<Dispute[]> {
    let query = db.select().from(disputes);

    const conditions = [];

    if (filters?.contractId) {
      conditions.push(eq(disputes.contractId, filters.contractId));
    }
    if (filters?.raisedBy) {
      conditions.push(eq(disputes.raisedBy, filters.raisedBy));
    }
    if (filters?.status) {
      conditions.push(eq(disputes.status, filters.status as any));
    }

    if (conditions.length > 0) {
      query = query.where(and(...conditions));
    }

    query = query.orderBy(desc(disputes.createdAt));

    if (filters?.limit) {
      query = query.limit(filters.limit);
    }
    if (filters?.offset) {
      query = query.offset(filters.offset);
    }

    return await query;
  }

  async getDispute(id: string): Promise<Dispute | undefined> {
    const [dispute] = await db.select().from(disputes).where(eq(disputes.id, id));
    return dispute || undefined;
  }

  async createDispute(dispute: InsertDispute): Promise<Dispute> {
    const [newDispute] = await db
      .insert(disputes)
      .values(dispute)
      .returning();
    return newDispute;
  }

  async updateDispute(id: string, updates: Partial<InsertDispute>): Promise<Dispute> {
    const [dispute] = await db
      .update(disputes)
      .set({ ...updates, updatedAt: new Date() })
      .where(eq(disputes.id, id))
      .returning();
    return dispute;
  }

  // Review methods
  async getReviews(filters?: {
    contractId?: string;
    reviewerId?: string;
    revieweeId?: string;
  }): Promise<Review[]> {
    let query = db.select().from(reviews);

    const conditions = [];

    if (filters?.contractId) {
      conditions.push(eq(reviews.contractId, filters.contractId));
    }
    if (filters?.reviewerId) {
      conditions.push(eq(reviews.reviewerId, filters.reviewerId));
    }
    if (filters?.revieweeId) {
      conditions.push(eq(reviews.revieweeId, filters.revieweeId));
    }

    if (conditions.length > 0) {
      query = query.where(and(...conditions));
    }

    query = query.orderBy(desc(reviews.createdAt));

    return await query;
  }

  async createReview(review: InsertReview): Promise<Review> {
    const [newReview] = await db
      .insert(reviews)
      .values(review)
      .returning();
    return newReview;
  }

  // Dashboard stats
  async getLandlordStats(landlordId: string): Promise<{
    totalProperties: number;
    activeContracts: number;
    monthlyRevenue: number;
    pendingVerifications: number;
  }> {
    const [propertiesCount] = await db
      .select({ count: sql<number>`count(*)` })
      .from(properties)
      .where(eq(properties.landlordId, landlordId));

    const [contractsCount] = await db
      .select({ count: sql<number>`count(*)` })
      .from(contracts)
      .where(and(eq(contracts.landlordId, landlordId), eq(contracts.status, "active")));

    const [revenueResult] = await db
      .select({ total: sql<number>`sum(cast(monthly_rent as decimal))` })
      .from(contracts)
      .where(and(eq(contracts.landlordId, landlordId), eq(contracts.status, "active")));

    const [pendingDocs] = await db
      .select({ count: sql<number>`count(*)` })
      .from(documents)
      .where(and(eq(documents.userId, landlordId), eq(documents.isVerified, false)));

    return {
      totalProperties: propertiesCount.count || 0,
      activeContracts: contractsCount.count || 0,
      monthlyRevenue: revenueResult.total || 0,
      pendingVerifications: pendingDocs.count || 0,
    };
  }

  async getTenantStats(tenantId: string): Promise<{
    currentRent: number;
    contractStatus: string;
    nextPaymentDate: Date | null;
    savedProperties: number;
  }> {
    const [activeContract] = await db
      .select()
      .from(contracts)
      .where(and(eq(contracts.tenantId, tenantId), eq(contracts.status, "active")))
      .limit(1);

    const [nextPayment] = await db
      .select()
      .from(payments)
      .where(and(eq(payments.tenantId, tenantId), eq(payments.status, "pending")))
      .orderBy(asc(payments.dueDate))
      .limit(1);

    return {
      currentRent: activeContract ? Number(activeContract.monthlyRent) : 0,
      contractStatus: activeContract?.status || "none",
      nextPaymentDate: nextPayment?.dueDate || null,
      savedProperties: 0, // This would require a favorites/saved properties table
    };
  }

  async getAdminStats(): Promise<{
    totalUsers: number;
    pendingVerifications: number;
    activeContracts: number;
    openDisputes: number;
  }> {
    const [usersCount] = await db
      .select({ count: sql<number>`count(*)` })
      .from(users);

    const [pendingVerifications] = await db
      .select({ count: sql<number>`count(*)` })
      .from(users)
      .where(eq(users.verificationStatus, "pending"));

    const [activeContracts] = await db
      .select({ count: sql<number>`count(*)` })
      .from(contracts)
      .where(eq(contracts.status, "active"));

    const [openDisputes] = await db
      .select({ count: sql<number>`count(*)` })
      .from(disputes)
      .where(eq(disputes.status, "open"));

    return {
      totalUsers: usersCount.count || 0,
      pendingVerifications: pendingVerifications.count || 0,
      activeContracts: activeContracts.count || 0,
      openDisputes: openDisputes.count || 0,
    };
  }
}

export const storage = new DatabaseStorage();

