import { Link, useLocation } from "wouter";
import { useAuth } from "@/hooks/use-auth";
import { useTheme } from "@/components/theme-provider";
import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { Badge } from "@/components/ui/badge";
import { Bell, Home, Moon, Sun, User, LogOut } from "lucide-react";

export function Header() {
  const { user, logout } = useAuth();
  const { theme, setTheme } = useTheme();
  const [location, setLocation] = useLocation();

  const handleLogout = () => {
    logout();
    setLocation("/");
  };

  return (
    <header className="bg-white dark:bg-gray-800 shadow-sm border-b border-gray-200 dark:border-gray-700 sticky top-0 z-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center h-16">
          {/* Logo */}
          <Link href="/" className="flex items-center" data-testid="link-home">
            <div className="flex-shrink-0 flex items-center">
              <div className="h-8 w-8 bg-primary-500 rounded-lg flex items-center justify-center">
                <Home className="text-white text-lg" />
              </div>
              <span className="ml-2 text-xl font-bold text-gray-900 dark:text-white">SmartRent</span>
              <Badge variant="secondary" className="ml-2 text-xs bg-primary-100 text-primary-700">BETA</Badge>
            </div>
          </Link>

          {/* Navigation */}
          <nav className="hidden md:flex space-x-8">
            <Link 
              href="/properties" 
              className={`px-3 py-2 text-sm font-medium transition-colors ${
                location === '/properties' 
                  ? 'text-gray-900 dark:text-white' 
                  : 'text-gray-500 dark:text-gray-300 hover:text-primary-600'
              }`}
              data-testid="link-properties"
            >
              Properties
            </Link>
            {user && (
              <>
                <Link 
                  href="/contracts" 
                  className={`px-3 py-2 text-sm font-medium transition-colors ${
                    location === '/contracts' 
                      ? 'text-gray-900 dark:text-white' 
                      : 'text-gray-500 dark:text-gray-300 hover:text-primary-600'
                  }`}
                  data-testid="link-contracts"
                >
                  Contracts
                </Link>
                <Link 
                  href="/payments" 
                  className={`px-3 py-2 text-sm font-medium transition-colors ${
                    location === '/payments' 
                      ? 'text-gray-900 dark:text-white' 
                      : 'text-gray-500 dark:text-gray-300 hover:text-primary-600'
                  }`}
                  data-testid="link-payments"
                >
                  Payments
                </Link>
              </>
            )}
          </nav>

          {/* Right side actions */}
          <div className="flex items-center space-x-4">
            {/* Theme Toggle */}
            <Button
              variant="ghost"
              size="sm"
              onClick={() => setTheme(theme === "light" ? "dark" : "light")}
              data-testid="button-theme-toggle"
            >
              <Sun className="h-[1.2rem] w-[1.2rem] rotate-0 scale-100 transition-all dark:-rotate-90 dark:scale-0" />
              <Moon className="absolute h-[1.2rem] w-[1.2rem] rotate-90 scale-0 transition-all dark:rotate-0 dark:scale-100" />
              <span className="sr-only">Toggle theme</span>
            </Button>

            {user ? (
              <>
                {/* Notifications */}
                <Button variant="ghost" size="sm" className="relative" data-testid="button-notifications">
                  <Bell className="h-5 w-5" />
                  <span className="absolute -top-1 -right-1 h-4 w-4 bg-warning-500 text-white text-xs rounded-full flex items-center justify-center">3</span>
                </Button>

                {/* User Menu */}
                <DropdownMenu>
                  <DropdownMenuTrigger asChild>
                    <Button variant="ghost" className="flex items-center space-x-3" data-testid="button-user-menu">
                      <div className="flex items-center space-x-2">
                        <div className="h-8 w-8 bg-gray-300 rounded-full flex items-center justify-center">
                          <User className="h-4 w-4 text-gray-600" />
                        </div>
                        <span className="hidden sm:block text-sm text-gray-700 dark:text-gray-300">{user.fullName}</span>
                        <Badge 
                          variant={user.verificationStatus === 'verified' ? 'default' : 'secondary'}
                          className={`hidden sm:block text-xs ${
                            user.verificationStatus === 'verified' 
                              ? 'bg-success-100 text-success-700' 
                              : 'bg-warning-100 text-warning-700'
                          }`}
                        >
                          {user.verificationStatus === 'verified' ? 'Verified' : 'Pending'}
                        </Badge>
                      </div>
                    </Button>
                  </DropdownMenuTrigger>
                  <DropdownMenuContent align="end">
                    <DropdownMenuItem asChild>
                      <Link href="/dashboard" className="flex items-center" data-testid="link-dashboard">
                        <User className="mr-2 h-4 w-4" />
                        Dashboard
                      </Link>
                    </DropdownMenuItem>
                    <DropdownMenuItem asChild>
                      <Link href="/verification" className="flex items-center" data-testid="link-verification">
                        <User className="mr-2 h-4 w-4" />
                        Verification
                      </Link>
                    </DropdownMenuItem>
                    <DropdownMenuItem onClick={handleLogout} data-testid="button-logout">
                      <LogOut className="mr-2 h-4 w-4" />
                      Logout
                    </DropdownMenuItem>
                  </DropdownMenuContent>
                </DropdownMenu>
              </>
            ) : (
              <div className="flex space-x-2">
                <Button variant="ghost" asChild data-testid="button-login">
                  <Link href="/login">Login</Link>
                </Button>
                <Button asChild data-testid="button-register">
                  <Link href="/register">Register</Link>
                </Button>
              </div>
            )}
          </div>
        </div>
      </div>
    </header>
  );
}

client/src/components/property-card.tsx.content:
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { MapPin, Bed, Bath, Expand, Star, Heart, User } from "lucide-react";
import { Link } from "wouter";

interface PropertyCardProps {
  property: {
    id: string;
    title: string;
    address: string;
    city: string;
    area: string;
    monthlyRent: string;
    propertyType: string;
    bedrooms?: number;
    bathrooms?: number;
    sqft?: number;
    images?: string[];
    isAvailable: boolean;
    landlord?: {
      fullName: string;
      rating?: number;
      reviewCount?: number;
      verificationStatus: string;
    };
    aiSuggestedPrice?: string;
  };
}

export function PropertyCard({ property }: PropertyCardProps) {
  const defaultImage = "https://images.unsplash.com/photo-1522708323590-d24dbb6b0267?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&h=600";
  const propertyImage = property.images && property.images.length > 0 ? property.images[0] : defaultImage;

  return (
    <Card className="bg-white dark:bg-gray-800 rounded-xl shadow-md hover:shadow-lg transition-shadow overflow-hidden border border-gray-200 dark:border-gray-700">
      <div className="relative">
        <img 
          src={propertyImage} 
          alt={property.title}
          className="w-full h-48 object-cover"
        />

        {/* Status Badges */}
        <div className="absolute top-3 left-3 flex space-x-2">
          {property.landlord?.verificationStatus === 'verified' && (
            <Badge className="bg-success-500 text-white text-xs">Verified</Badge>
          )}
          <Badge className="bg-primary-500 text-white text-xs">Smart Contract</Badge>
        </div>

        {/* AI Badge */}
        {property.aiSuggestedPrice && (
          <div className="absolute top-3 right-3">
            <Badge className="bg-warning-500 text-white text-xs">AI Recommended</Badge>
          </div>
        )}

        {/* Favorite Button */}
        <Button 
          variant="secondary" 
          size="sm"
          className="absolute bottom-3 right-3 w-8 h-8 p-0 bg-white dark:bg-gray-800 rounded-full shadow-md hover:bg-gray-50 transition-colors"
          data-testid={`button-favorite-${property.id}`}
        >
          <Heart className="h-4 w-4 text-gray-600 dark:text-gray-400" />
        </Button>
      </div>

      <CardContent className="p-6">
        <div className="flex justify-between items-start mb-2">
          <Link href={`/properties/${property.id}`} className="flex-1" data-testid={`link-property-${property.id}`}>
            <h3 className="text-lg font-semibold text-gray-900 dark:text-white hover:text-primary-600 transition-colors">
              {property.title}
            </h3>
          </Link>
          <div className="text-right ml-4">
            <div className="text-xl font-bold text-gray-900 dark:text-white">
              ₨{Number(property.monthlyRent).toLocaleString()}
            </div>
            <div className="text-sm text-gray-500 dark:text-gray-400">/month</div>
          </div>
        </div>

        <div className="flex items-center text-gray-600 dark:text-gray-400 text-sm mb-3">
          <MapPin className="mr-1 h-4 w-4" />
          <span>{property.area}, {property.city}</span>
        </div>

        <div className="flex items-center space-x-4 text-sm text-gray-600 dark:text-gray-400 mb-4">
          {property.bedrooms && (
            <span className="flex items-center">
              <Bed className="mr-1 h-4 w-4" />
              {property.bedrooms} Bed
            </span>
          )}
          {property.bathrooms && (
            <span className="flex items-center">
              <Bath className="mr-1 h-4 w-4" />
              {property.bathrooms} Bath
            </span>
          )}
          {property.sqft && (
            <span className="flex items-center">
              <Expand className="mr-1 h-4 w-4" />
              {property.sqft.toLocaleString()} sq ft
            </span>
          )}
        </div>

        {/* Landlord Info */}
        {property.landlord && (
          <div className="flex items-center justify-between pt-4 border-t border-gray-200 dark:border-gray-700">
            <div className="flex items-center space-x-2">
              <div className="w-8 h-8 bg-gray-300 rounded-full flex items-center justify-center">
                <User className="h-4 w-4 text-gray-600" />
              </div>
              <div>
                <div className="text-sm font-medium text-gray-900 dark:text-white">
                  {property.landlord.fullName}
                </div>
                {property.landlord.rating && (
                  <div className="flex items-center space-x-1">
                    <div className="flex text-yellow-400 text-xs">
                      {[...Array(5)].map((_, i) => (
                        <Star 
                          key={i} 
                          className={`h-3 w-3 ${i < Math.floor(property.landlord.rating || 0) ? 'fill-current' : ''}`} 
                        />
                      ))}
                    </div>
                    <span className="text-xs text-gray-500 dark:text-gray-400">
                      ({property.landlord.reviewCount || 0} reviews)
                    </span>
                  </div>
                )}
              </div>
            </div>
            <Badge 
              variant={property.landlord.verificationStatus === 'verified' ? 'default' : 'secondary'}
              className={`text-xs ${
                property.landlord.verificationStatus === 'verified' 
                  ? 'bg-success-100 text-success-700' 
                  : 'bg-warning-100 text-warning-700'
              }`}
            >
              {property.landlord.verificationStatus === 'verified' ? 'Verified' : 'Pending'}
            </Badge>
          </div>
        )}
      </CardContent>
    </Card>
  );
}

client/src/components/search-filters.tsx.content:
import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Checkbox } from "@/components/ui/checkbox";
import { Badge } from "@/components/ui/badge";
import { Search, MapPin } from "lucide-react";

interface SearchFiltersProps {
  onSearch: (filters: {
    city: string;
    propertyType: string;
    minRent: string;
    maxRent: string;
    bedrooms: string;
    aiSuggestions: boolean;
  }) => void;
}

export function SearchFilters({ onSearch }: SearchFiltersProps) {
  const [filters, setFilters] = useState({
    city: "",
    propertyType: "",
    minRent: "",
    maxRent: "",
    bedrooms: "",
    aiSuggestions: false,
  });

  const handleSearch = () => {
    onSearch(filters);
  };

  const updateFilter = (key: string, value: string | boolean) => {
    setFilters(prev => ({ ...prev, [key]: value }));
  };

  return (
    <section className="bg-white dark:bg-gray-800 shadow-sm border-b border-gray-200 dark:border-gray-700 -mt-8 relative z-10">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="bg-white dark:bg-gray-800 rounded-xl shadow-lg border border-gray-200 dark:border-gray-700 p-6">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 xl:grid-cols-6 gap-4">
            {/* Location */}
            <div className="lg:col-span-2">
              <Label htmlFor="location" className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                Location
              </Label>
              <div className="relative">
                <MapPin className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 h-4 w-4" />
                <Input
                  id="location"
                  type="text"
                  placeholder="Lahore, Karachi, Islamabad..."
                  className="pl-10"
                  value={filters.city}
                  onChange={(e) => updateFilter('city', e.target.value)}
                  data-testid="input-location"
                />
              </div>
            </div>

            {/* Property Type */}
            <div>
              <Label htmlFor="property-type" className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                Type
              </Label>
              <Select value={filters.propertyType} onValueChange={(value) => updateFilter('propertyType', value)}>
                <SelectTrigger data-testid="select-property-type">
                  <SelectValue placeholder="All Types" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="">All Types</SelectItem>
                  <SelectItem value="apartment">Apartment</SelectItem>
                  <SelectItem value="house">House</SelectItem>
                  <SelectItem value="commercial">Commercial</SelectItem>
                  <SelectItem value="office">Office</SelectItem>
                </SelectContent>
              </Select>
            </div>

            {/* Budget Range */}
            <div>
              <Label htmlFor="budget" className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                Budget (PKR)
              </Label>
              <Select value={`${filters.minRent}-${filters.maxRent}`} onValueChange={(value) => {
                const [min, max] = value.split('-');
                updateFilter('minRent', min);
                updateFilter('maxRent', max);
              }}>
                <SelectTrigger data-testid="select-budget">
                  <SelectValue placeholder="Any Budget" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="-">Any Budget</SelectItem>
                  <SelectItem value="10000-25000">10k - 25k</SelectItem>
                  <SelectItem value="25000-50000">25k - 50k</SelectItem>
                  <SelectItem value="50000-100000">50k - 100k</SelectItem>
                  <SelectItem value="100000-">100k+</SelectItem>
                </SelectContent>
              </Select>
            </div>

            {/* Bedrooms */}
            <div>
              <Label htmlFor="bedrooms" className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                Bedrooms
              </Label>
              <Select value={filters.bedrooms} onValueChange={(value) => updateFilter('bedrooms', value)}>
                <SelectTrigger data-testid="select-bedrooms">
                  <SelectValue placeholder="Any" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="">Any</SelectItem>
                  <SelectItem value="1">1</SelectItem>
                  <SelectItem value="2">2</SelectItem>
                  <SelectItem value="3">3+</SelectItem>
                </SelectContent>
              </Select>
            </div>

            {/* Search Button */}
            <div className="flex items-end">
              <Button 
                onClick={handleSearch} 
                className="w-full bg-primary-600 hover:bg-primary-700 text-white"
                data-testid="button-search"
              >
                <Search className="mr-2 h-4 w-4" />
                Search
              </Button>
            </div>
          </div>

